const allOrders = $('Read All Orders').all().map(i => i.json);
const allWorkers = $('Read All Workers').all().map(i => i.json);

// Сегодняшняя дата (MSK = UTC+3)
const now = new Date();
const mskOffset = 3 * 60 * 60 * 1000;
const mskNow = new Date(now.getTime() + mskOffset);
const todayStr = mskNow.toISOString().slice(0, 10); // YYYY-MM-DD

// Фильтруем заказы за сегодня
const todayOrders = allOrders.filter(o => {
  if (!o.created_at) return false;
  const orderDate = new Date(o.created_at);
  const orderMsk = new Date(orderDate.getTime() + mskOffset);
  return orderMsk.toISOString().slice(0, 10) === todayStr;
});

const total = todayOrders.length;
const published = todayOrders.filter(o => o.status === 'published').length;
const closed = todayOrders.filter(o => o.status === 'closed').length;
const pending = todayOrders.filter(o => o.status === 'pending').length;
const cancelled = todayOrders.filter(o => o.status === 'cancelled').length;
const revenue = (closed + published) * 500; // 500р за публикацию
const conversion = total > 0 ? Math.round(closed / total * 100) : 0;

// Топ исполнитель дня
const todayExecutors = todayOrders
  .filter(o => o.status === 'closed' && o.executor_id)
  .reduce((acc, o) => {
    acc[o.executor_id] = (acc[o.executor_id] || 0) + 1;
    return acc;
  }, {});

let topWorker = 'нет данных';
const topExecutorId = Object.entries(todayExecutors)
  .sort((a, b) => b[1] - a[1])[0];

if (topExecutorId) {
  const w = allWorkers.find(w => String(w.telegram_id) === String(topExecutorId[0]));
  if (w) {
    topWorker = `${w.name || w.username} (⭐${w.rating}, ${topExecutorId[1]} заказов)`;
  }
}

// Общая статистика
const totalWorkers = allWorkers.length;
const activeWorkers = allWorkers.filter(w => parseInt(w.jobs_count || 0) > 0).length;
const vipWorkers = allWorkers.filter(w => w.is_vip === 'TRUE' || w.is_vip === true).length;

const dateFormatted = mskNow.toLocaleDateString('ru-RU', {
  day: '2-digit', month: '2-digit', year: 'numeric'
});

return [{
  json: {
    date: dateFormatted,
    total, published, closed, pending, cancelled,
    revenue, conversion,
    topWorker,
    totalWorkers, activeWorkers, vipWorkers,
    totalAllOrders: allOrders.length
  }
}];

